/**
 * Fix Script: Recompute totalVariation for offline SMIB collection reports
 *
 * Old offline SMIB collections have sasMeters.gross = 0 stored (no live SAS data existed
 * at collection time). The original computeTotalVariation read this as $0 SAS and computed
 * meterGross - 0 = meterGross, producing phantom variation.
 *
 * This script applies the corrected logic: when sasMeters.gross = 0 AND sasMeters.drop = 0
 * for a SMIB machine, treat effectiveSasGross = movement.gross → variation = 0.
 *
 * Usage:
 *   bun run scripts/fix-offline-variation.ts <locationReportId>    # Fix one report
 *   bun run scripts/fix-offline-variation.ts --all                  # Fix all affected reports
 *
 * The script is read-only by default — add --write to commit the update to MongoDB.
 */

import mongoose from 'mongoose';

const MONGODB_URI =
  process.env.MONGODB_URI ||
  'mongodb://sunny1:87ydaiuhdsia2e@147.182.133.136:27017/sas-aaron?authSource=admin';

type CollectionRow = {
  _id: string;
  machineId?: string;
  movement?: { gross?: number };
  sasMeters?: {
    gross?: number | null;
    drop?: number | null;
    jackpot?: number | null;
    sasStartTime?: unknown;
    sasEndTime?: unknown;
  };
};

async function computeCorrectVariation(
  colls: CollectionRow[],
  smibMap: Map<string, boolean>,
  includeJackpot: boolean
): Promise<number> {
  return colls.reduce((sum, col) => {
    const hasSmib = smibMap.get(String(col.machineId)) ?? false;
    if (!hasSmib) return sum;

    const meterGross = col.movement?.gross ?? 0;
    const storedSasGross = col.sasMeters?.gross;

    if (storedSasGross === undefined || storedSasGross === null) return sum;

    // Offline SMIB heuristic: sasMeters.gross = 0 AND sasMeters.drop = 0 means no live
    // SAS data existed — use movement.gross so variation = 0.
    const effectiveSasGross =
      storedSasGross === 0 && (col.sasMeters?.drop ?? 0) === 0
        ? meterGross
        : storedSasGross;

    const machineJackpot = col.sasMeters?.jackpot ?? 0;
    const adjustedSasGross = includeJackpot
      ? effectiveSasGross - machineJackpot
      : effectiveSasGross;

    return sum + (meterGross - adjustedSasGross);
  }, 0);
}

async function fixReport(
  db: mongoose.mongo.Db,
  locationReportId: string,
  write: boolean
): Promise<{ before: number | null; after: number; changed: boolean }> {
  const collReports = db.collection('collectionreports');
  const collections = db.collection('collections');
  const machines = db.collection('machines');
  const gamingLocations = db.collection('gaminglocations');
  const licencees = db.collection('licencees');

  const report = await collReports.findOne(
    { locationReportId },
    { projection: { location: 1, totalVariation: 1 } }
  );
  if (!report) throw new Error(`Report not found: ${locationReportId}`);

  const colls = (await collections
    .find(
      { locationReportId },
      { projection: { movement: 1, sasMeters: 1, machineId: 1 } }
    )
    .toArray()) as CollectionRow[];

  if (!colls.length) return { before: report.totalVariation as number | null, after: 0, changed: false };

  const machineIds = colls
    .map(col => col.machineId)
    .filter((id): id is string => Boolean(id));

  let smibMap = new Map<string, boolean>();
  if (machineIds.length) {
    const machineDocs = await machines
      .find({ _id: { $in: machineIds } }, { projection: { _id: 1, relayId: 1 } })
      .toArray();
    smibMap = new Map(
      machineDocs.map(m => [String(m._id), Boolean((m.relayId as string)?.trim())])
    );
  }

  let includeJackpot = false;
  const locationId = report.location as string | undefined;
  if (locationId) {
    const location = await gamingLocations.findOne(
      { _id: locationId },
      { projection: { 'rel.licencee': 1 } }
    );
    if (location?.rel?.licencee) {
      const licencee = await licencees.findOne(
        { _id: location.rel.licencee },
        { projection: { includeJackpot: 1 } }
      );
      includeJackpot = Boolean(licencee?.includeJackpot);
    }
  }

  const computed = await computeCorrectVariation(colls, smibMap, includeJackpot);
  const rounded = Number(computed.toFixed(2));
  const before = typeof report.totalVariation === 'number' ? (report.totalVariation as number) : null;
  const changed = before === null || Math.abs(before - rounded) > 0.01;

  if (changed && write) {
    await collReports.updateOne(
      { locationReportId },
      { $set: { totalVariation: rounded } }
    );
  }

  return { before, after: rounded, changed };
}

async function main() {
  const args = process.argv.slice(2);
  const allMode = args.includes('--all');
  const write = args.includes('--write');
  const targetId = args.find(arg => !arg.startsWith('--'));

  if (!allMode && !targetId) {
    console.error('Usage: bun run scripts/fix-offline-variation.ts <locationReportId> [--write]');
    console.error('       bun run scripts/fix-offline-variation.ts --all [--write]');
    process.exit(1);
  }

  console.log(`\n🔧 fix-offline-variation — mode=${allMode ? 'all' : 'single'} write=${write}`);
  if (!write) console.log('   (dry run — add --write to commit changes)\n');

  await mongoose.connect(MONGODB_URI);
  console.log('✅ Connected to MongoDB\n');

  try {
    const db = mongoose.connection.db!;
    const collReports = db.collection('collectionreports');

    let reportIds: string[];

    if (allMode) {
      // Target reports where totalVariation != 0 and have SMIB machines with gross=0 collections
      const cursor = collReports.find(
        {
          locationReportId: { $exists: true, $ne: null },
          totalVariation: { $ne: 0, $ne: null, $exists: true },
        },
        { projection: { locationReportId: 1 } }
      );
      const docs = await cursor.toArray();
      reportIds = docs.map(d => d.locationReportId as string).filter(Boolean);
      console.log(`📊 Found ${reportIds.length} non-zero variation reports to check\n`);
    } else {
      reportIds = [targetId!];
    }

    let checked = 0;
    let changed = 0;
    let errors = 0;

    for (const locationReportId of reportIds) {
      checked++;
      try {
        const result = await fixReport(db, locationReportId, write);

        if (result.changed) {
          changed++;
          const action = write ? '✅ UPDATED' : '📋 WOULD UPDATE';
          console.log(`${action}  ${locationReportId}`);
          console.log(`         before=${result.before ?? 'null'}  after=${result.after}`);
        } else if (!allMode) {
          console.log(`✅ No change needed: ${locationReportId}`);
          console.log(`   stored=${result.before}  computed=${result.after}`);
        }
      } catch (err) {
        errors++;
        console.error(`❌ Error on ${locationReportId}:`, err instanceof Error ? err.message : String(err));
      }
    }

    console.log(`\n📊 Done: checked=${checked}  changed=${changed}  errors=${errors}`);
    if (!write && changed > 0) {
      console.log('\n   Re-run with --write to apply the changes.');
    }
  } finally {
    await mongoose.disconnect();
    console.log('🔌 Disconnected\n');
  }
}

main().catch(err => {
  console.error('❌ Fatal:', err instanceof Error ? err.message : String(err));
  process.exit(1);
});

/**
 * Collection Report Calculations Helper Functions
 *
 * Provides backend helper functions for calculating financial totals for collection reports,
 * including drop, cancelled credits, gross, and SAS gross metrics. It aggregates
 * values from machine collections and meters data to provide comprehensive report totals.
 *
 * Features:
 * - Calculates total drop and cancelled credits from machine collections.
 * - Calculates total gross (drop - cancelled credits).
 * - Calculates total SAS gross from meters collection movement data.
 */

import { Collections } from '@/app/api/lib/models/collections';
import { Machine } from '@/app/api/lib/models/machines';
import { GamingLocations } from '@/app/api/lib/models/gaminglocations';
import type { CreateCollectionReportPayload } from '@/lib/types/api';
import type {
  CollectionDocument,
  CollectionReportMachineEntry,
} from '@/lib/types/collection';

// ============================================================================
// Collection Report Total Calculations
// ============================================================================

/**
 * Calculates totalDrop, totalCancelled, totalGross, and totalSasGross for a collection report.
 * Optimization: Uses existing Collections documents instead of querying raw Meters.
 * @param {CreateCollectionReportPayload & { machines?: CollectionReportMachineEntry[]; collectionIds?: string[] }} payload - The raw payload from the frontend.
 * @returns {Promise<{ totalDrop: number; totalCancelled: number; totalGross: number; totalSasGross: number; totalJackpot: number }>} An object with calculated totals.
 */
export async function calculateCollectionReportTotals(
  payload: CreateCollectionReportPayload & {
    machines?: CollectionReportMachineEntry[];
    collectionIds?: string[]; // Optional: collection _id array to avoid queries
  }
) {
  if (!payload || typeof payload !== 'object') {
    console.error('[calculateCollectionReportTotals] payload is required');
    return {
      totalDrop: 0,
      totalCancelled: 0,
      totalGross: 0,
      totalSasGross: 0,
      totalJackpot: 0,
    };
  }
  console.log(
    '🔄 [Calculations] Starting collection report totals calculation...'
  );
  const machines: CollectionReportMachineEntry[] = payload.machines || [];
  const collectionIds = payload.collectionIds || [];
  let totalDrop = 0;
  let totalCancelled = 0;
  let totalSasGross = 0;
  let totalJackpot = 0;

  console.log(
    '🔄 [Calculations] Processing ' +
      machines.length +
      (machines.length === 1 ? ' machine' : ' machines'),
    {
      hasCollectionIds: collectionIds.length > 0,
      collectionIdsCount: collectionIds.length,
      includeJackpot: payload.includeJackpot,
    }
  );

  // Helper function to query collection by machineId and meters (fallback method)
  const queryCollectionByMachine = async (
    machineEntry: CollectionReportMachineEntry,
    reportTimestamp: Date
  ) => {
    const minTimestamp = new Date(
      reportTimestamp.getTime() - 24 * 60 * 60 * 1000
    );
    const collectionQuery = {
      machineId: machineEntry.machineId,
      metersIn: Number(machineEntry.metersIn),
      metersOut: Number(machineEntry.metersOut),
      timestamp: { $gte: minTimestamp },
      $or: [{ locationReportId: '' }, { locationReportId: { $exists: false } }],
    };

    return Collections.findOne(collectionQuery)
      .sort({ timestamp: -1 })
      .maxTimeMS(10000) // 10 second timeout per query
      .lean<CollectionDocument>();
  };

  // Get report timestamp to filter recent collections only
  const reportTimestamp = payload.timestamp
    ? new Date(payload.timestamp)
    : new Date();

  // If we have collection IDs, use them directly (much faster)
  if (collectionIds.length > 0 && collectionIds.length === machines.length) {
    console.log('🔄 [Calculations] Using collection IDs for direct lookup...');
    for (let machineIndex = 0; machineIndex < machines.length; machineIndex++) {
      const machine = machines[machineIndex];
      const collectionId = collectionIds[machineIndex];

      if (!machine.machineId) continue;

      let collection: CollectionDocument | null = null;

      // Try direct lookup by collection ID first
      if (collectionId) {
        try {
          collection = await Collections.findOne({ _id: collectionId })
            .maxTimeMS(10000)
            .lean<CollectionDocument>();
        } catch (err) {
          console.error(
            `❌ [Calculations] Error looking up collection ${collectionId}:`,
            err
          );
        }
      }

      // If direct lookup failed, try query method as fallback
      if (!collection) {
        try {
          collection = await queryCollectionByMachine(machine, reportTimestamp);
        } catch (err) {
          console.error(
            `❌ [Calculations] Error querying collection for machine ${machine.machineId}:`,
            err
          );
        }
      }

      // Process the collection if found
      if (collection) {
        const moveIn = collection.movement?.metersIn || 0;
        const moveOut = collection.movement?.metersOut || 0;
        const jackpot = collection.sasMeters?.jackpot || 0;

        totalDrop += moveIn;
        totalCancelled += moveOut;
        totalJackpot += jackpot;

        const sasGross = collection.sasMeters?.gross || 0;
        totalSasGross += sasGross;
      }
    }
  } else {
    // Fallback: Query by machineId and meters (original method)
    for (const machine of machines) {
      if (!machine.machineId) continue;

      try {
        const collection = await queryCollectionByMachine(
          machine,
          reportTimestamp
        );

        if (collection) {
          const moveIn = collection.movement?.metersIn || 0;
          const moveOut = collection.movement?.metersOut || 0;
          const jackpot = collection.sasMeters?.jackpot || 0;

          totalDrop += moveIn;
          totalCancelled += moveOut;
          totalJackpot += jackpot;

          const sasGross = collection.sasMeters?.gross || 0;
          totalSasGross += sasGross;
        }
      } catch (err) {
        console.error(
          `❌ [Calculations] Error processing machine ${machine.machineId}:`,
          err
        );
      }
    }
  }

  // Apply includeJackpot logic
  // If enabled, totalCancelled is adjusted (Money Out = Cancelled Credits + Jackpots)
  const useIncludeJackpot = !!payload.includeJackpot;
  const effectiveTotalCancelled = useIncludeJackpot
    ? totalCancelled + totalJackpot
    : totalCancelled;

  const totalGross = totalDrop - effectiveTotalCancelled;
  const effectiveTotalSasGross = useIncludeJackpot
    ? Math.max(0, totalSasGross - totalJackpot)
    : totalSasGross;

  console.log('✅ [Calculations] Totals calculated:', {
    totalDrop,
    totalCancelled,
    totalJackpot,
    useIncludeJackpot,
    effectiveTotalCancelled,
    totalGross,
    totalSasGross,
    effectiveTotalSasGross,
  });

  return {
    totalDrop,
    totalCancelled: effectiveTotalCancelled,
    totalGross,
    totalSasGross: effectiveTotalSasGross,
    totalJackpot, // Include raw jackpot total for reference
  };
}

// ============================================================================
// Total Variation Calculation
// ============================================================================

/**
 * Computes total variation from stored collections (movement.gross - adjustedSasGross)
 * for a given collection report, respecting hasSmib filtering and includeJackpot.
 */
export async function computeTotalVariation(
  locationReportId: string,
  locationId?: string
): Promise<number> {
  const collections = await Collections.find(
    { locationReportId },
    { movement: 1, sasMeters: 1, machineId: 1 }
  ).lean<Pick<CollectionDocument, 'movement' | 'sasMeters' | 'machineId'>[]>();

  if (!collections.length) return 0;

  // Fetch relayId per machine for SMIB filtering
  const machineIds = collections
    .map(c => c.machineId)
    .filter((id): id is string => Boolean(id));

  let smibMap = new Map<string, boolean>();
  if (machineIds.length) {
    const machines = await Machine.find(
      { _id: { $in: machineIds } },
      { relayId: 1 }
    ).lean<{ _id: string; relayId?: string }[]>();
    smibMap = new Map(
      machines.map(m => [String(m._id), Boolean(m.relayId?.trim())])
    );
  }

  // Check includeJackpot from licencee
  let includeJackpot = false;
  if (locationId) {
    const location = await GamingLocations.findOne(
      { _id: locationId },
      { 'rel.licencee': 1 }
    ).lean<{ rel?: { licencee?: string } } | null>();
    if (location?.rel?.licencee) {
      const { Licencee } = await import('@/app/api/lib/models/licencee');
      const licencee = await Licencee.findOne(
        { _id: location.rel.licencee },
        { includeJackpot: 1 }
      ).lean<{ includeJackpot?: boolean } | null>();
      includeJackpot = Boolean(licencee?.includeJackpot);
    }
  }

  // Use stored sasMeters.gross from each collection document.
  // This matches what Machine Metrics displays and is correct for both online and
  // offline SMIB machines. Re-querying the live Meters collection causes double-counting
  // for offline machines: pre-offline SAS meters + the supplemental COLLECTION_REPORT
  // meter both fall in the window, inflating SAS gross and producing phantom variation.
  return collections.reduce((sum, col) => {
    const hasSmib = smibMap.get(String(col.machineId)) ?? false;
    if (!hasSmib) return sum;

    const meterGross = col.movement?.gross ?? 0;
    const storedSasGross = col.sasMeters?.gross;

    // No stored SAS data means this machine had no SMIB data — skip variation.
    if (storedSasGross === undefined || storedSasGross === null) return sum;

    // When sasMeters.gross === 0 AND sasMeters.drop === 0, the machine had no live SAS
    // data at collection time (offline SMIB, pre-fix). Use movement.gross as the SAS
    // gross so variation = 0, which is the correct business result for offline machines.
    const effectiveSasGross =
      storedSasGross === 0 && (col.sasMeters?.drop ?? 0) === 0
        ? meterGross
        : storedSasGross;

    const machineJackpot = col.sasMeters?.jackpot ?? 0;
    const adjustedSasGross = includeJackpot
      ? effectiveSasGross - machineJackpot
      : effectiveSasGross;

    return sum + (meterGross - adjustedSasGross);
  }, 0);
}

/**
 * useCollectionReportVariationCheck
 *
 * Hook for checking variations in unsaved collection report data before submission.
 * Manages loading, error, and minimized states for variation checking.
 *
 * Features:
 * - Calls /api/collection-reports/check-variations endpoint
 * - Automatically re-checks when machines data changes (with debounce)
 * - Manages UI states (checking, complete, error, minimized)
 * - Pre-creates manual meter documents for offline/non-SMIB machines before
 *   the variation check fires, with per-machine progress state
 * - Provides methods to toggle minimize state and reset
 */

import { useState, useCallback, useRef, useEffect } from 'react';

export type CheckVariationsMachine = {
  machineId: string;
  machineName?: string;
  metersIn: number;
  metersOut: number;
  sasStartTime?: string | Date;
  sasEndTime?: string | Date;
  prevMetersIn?: number;
  prevMetersOut?: number;
  /** Pre-calculated movement gross from a saved collection document (e.g. collection.movement.gross).
   * When provided the API uses this value directly instead of recalculating from raw meters,
   * which ensures RAM-clear entries produce the same meterGross as the report detail page. */
  movementGross?: number;
  /** Pre-computed SAS gross from a saved collection's sasMeters.gross.
   * When provided the API uses this value directly instead of querying live Meters,
   * which prevents offline SMIB machines from showing phantom variation. */
  storedSasGross?: number;
}

export type MachineVariationData = {
  machineId: string;
  machineName: string;
  variation: number | string;
  sasGross: number | string;
  meterGross: number;
  sasStartTime?: string | Date | null;
  sasEndTime?: string | Date | null;
}

export type VariationsCheckResponse = {
  hasVariations: boolean;
  totalVariation: number;
  machines: MachineVariationData[];
}

export type PreCreateMeterPayload = {
  machineId: string;
  collectionId?: string;
  locationId: string;
  sessionId?: string;
  metersIn: number;
  metersOut: number;
  prevMetersIn: number;
  prevMetersOut: number;
  customName?: string;
  ramClear?: boolean;
  ramClearMetersIn?: number;
  ramClearMetersOut?: number;
  sasEndTime?: string | Date;
};

type VariationCheckState = {
  isChecking: boolean;
  checkComplete: boolean;
  hasVariations: boolean | null;
  variationsData: VariationsCheckResponse | null;
  error: string | null;
  isMinimized: boolean;
  isPreCreating: boolean;
  currentMeterMachineName: string | null;
  meterCreationError: string | null;
}

const DEFAULT_STATE: VariationCheckState = {
  isChecking: false,
  checkComplete: false,
  hasVariations: null,
  variationsData: null,
  error: null,
  isMinimized: false,
  isPreCreating: false,
  currentMeterMachineName: null,
  meterCreationError: null,
};

type UseVariationCheckOptions = {
  autoCheckOnEdit?: boolean; // Auto re-check when machines change
  debounceMs?: number; // Debounce delay for auto-check
}

export function useCollectionReportVariationCheck(
  options: UseVariationCheckOptions = {}
) {
  // ============================================================================
  // State & Hooks
  // ============================================================================
  const { debounceMs = 500 } = options;

  const [state, setState] = useState<VariationCheckState>(DEFAULT_STATE);
  const lastMachinesRef = useRef<CheckVariationsMachine[] | null>(null);
  const debounceTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  // ============================================================================
  // Handlers
  // ============================================================================

  /**
   * Check variations for the given machines in a location
   */
  const checkVariations = useCallback(
    async (
      locationId: string,
      machines: CheckVariationsMachine[],
      includeJackpot?: boolean
    ) => {
      if (!locationId) {
        setState(prev => ({ ...prev, error: 'Invalid location' }));
        return;
      }

      // If no machines to check (e.g. all machines are offline), trivially
      // no variations — skip the API call entirely.
      if (machines.length === 0) {
        setState({
          ...DEFAULT_STATE,
          checkComplete: true,
          hasVariations: false,
          variationsData: {
            hasVariations: false,
            totalVariation: 0,
            machines: [],
          },
        });
        return;
      }

      setState({
        ...DEFAULT_STATE,
        isChecking: true,
      });

      try {
        const response = await fetch(
          '/api/collection-reports/check-variations',
          {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              locationId,
              machines,
              includeJackpot,
            }),
          }
        );

        if (!response.ok) {
          const errorData = await response.json();
          throw new Error(errorData.message || 'Failed to check variations');
        }

        const data = await response.json();

        setState(prev => ({
          ...prev,
          isChecking: false,
          checkComplete: true,
          hasVariations: data.data.hasVariations,
          variationsData: data.data,
          error: null,
        }));
      } catch (err) {
        const errorMessage =
          err instanceof Error ? err.message : 'Unknown error occurred';
        setState(prev => ({
          ...prev,
          isChecking: false,
          checkComplete: false,
          hasVariations: null,
          variationsData: null,
          error: errorMessage,
        }));
      }
    },
    []
  );

  /**
   * Auto re-check when machines change (with debounce)
   */
  const triggerAutoCheck = useCallback(
    (
      locationId: string,
      machines: CheckVariationsMachine[],
      includeJackpot?: boolean
    ) => {
      // Debounce re-checks
      if (debounceTimeoutRef.current) {
        clearTimeout(debounceTimeoutRef.current);
      }

      debounceTimeoutRef.current = setTimeout(() => {
        // Only check if we have a previous check and machines have changed
        if (state.checkComplete && machines.length > 0) {
          checkVariations(locationId, machines, includeJackpot);
        }
      }, debounceMs);

      lastMachinesRef.current = machines;
    },
    [state.checkComplete, checkVariations, debounceMs]
  );

  /**
   * Toggle minimize state
   */
  const toggleMinimize = useCallback(() => {
    setState(prev => ({
      ...prev,
      isMinimized: !prev.isMinimized,
    }));
  }, []);

  /**
   * Pre-create manual meters for offline/non-SMIB machines, then run the
   * variation check. Shows per-machine progress in the UI.
   *
   * - If no preCreatePayloads are provided, skips straight to checkVariations.
   * - On any meter-creation failure, sets meterCreationError and stops — the
   *   variation check does NOT run.
   */
  const preCreateThenCheck = useCallback(
    async (
      locationId: string,
      variationMachines: CheckVariationsMachine[],
      preCreatePayloads: PreCreateMeterPayload[],
      includeJackpot?: boolean
    ) => {
      if (!locationId || (variationMachines.length === 0 && preCreatePayloads.length === 0)) {
        setState(prev => ({ ...prev, error: 'Invalid location or machines' }));
        return;
      }

      console.log(
        `[preCreateThenCheck] ▶️ location=${locationId} preCreatePayloads=${preCreatePayloads.length} variationMachines=${variationMachines.length}`
      );

      // ============================================================
      // Phase 1: Pre-create meters for offline/non-SMIB machines
      // ============================================================
      if (preCreatePayloads.length > 0) {
        setState({
          ...DEFAULT_STATE,
          isPreCreating: true,
        });

        // Track whether any meter was actually written to the DB so we can
        // guarantee the "Creating Manual Meters" message stays visible long
        // enough for the user to read it.  React renders are macro-tasks; very
        // fast local-dev fetches complete as microtasks before the first paint,
        // so without an explicit floor the message can be skipped entirely.
        const preCreateStartTime = Date.now();
        let anyMeterCreated = false;

        for (const payload of preCreatePayloads) {
          setState(prev => ({
            ...prev,
            currentMeterMachineName: payload.customName ?? 'Machine',
          }));

          console.log(
            `[preCreateThenCheck] 📤 POST pre-create-meters machine=${payload.machineId} ` +
              `customName="${payload.customName ?? 'Machine'}" collection=${payload.collectionId ?? 'none'}`
          );

          try {
            const response = await fetch(
              '/api/collection-reports/pre-create-meters',
              {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                  ...payload,
                  sasEndTime:
                    payload.sasEndTime instanceof Date
                      ? payload.sasEndTime.toISOString()
                      : payload.sasEndTime,
                }),
              }
            );

            const data = await response.json();

            console.log(
              `[preCreateThenCheck] 📥 Response machine=${payload.machineId} status=${response.status} ` +
                `success=${data.success} created=${data.created} skipped=${data.skipped} error=${data.error ?? 'none'}`
            );

            if (!response.ok || !data.success) {
              const displayName =
                data.customName ?? payload.customName ?? 'Machine';
              console.error(
                `[preCreateThenCheck] ❌ Failed for machine=${payload.machineId} ("${displayName}"): ${data.error ?? 'unknown'}`
              );
              setState(prev => ({
                ...prev,
                isPreCreating: false,
                currentMeterMachineName: displayName,
                meterCreationError:
                  data.error ?? 'Failed to create meter documents',
              }));
              return;
            }

            if (data.created) {
              anyMeterCreated = true;
            } else if (!data.skipped) {
              const displayName =
                data.customName ?? payload.customName ?? 'Machine';
              console.error(
                `[preCreateThenCheck] ❌ Meter not created and not skipped for machine=${payload.machineId} ("${displayName}")`
              );
              setState(prev => ({
                ...prev,
                isPreCreating: false,
                currentMeterMachineName: displayName,
                meterCreationError: `Failed to create meter for ${displayName}`,
              }));
              return;
            }
          } catch (err) {
            console.error(
              `[preCreateThenCheck] ❌ Network error for machine=${payload.machineId}:`,
              err instanceof Error ? err.message : 'Unknown error'
            );
            setState(prev => ({
              ...prev,
              isPreCreating: false,
              meterCreationError:
                err instanceof Error ? err.message : 'Unknown error occurred',
            }));
            return;
          }
        }

        console.log(
          `[preCreateThenCheck] Phase 1 complete — anyMeterCreated=${anyMeterCreated}`
        );

        // If meters were created, hold the message on screen for at least
        // 1 second — this is the explicit visual confirmation that the meter
        // exists before the variation check fires.  Online SMIB machines that
        // were skipped (data.created === false) get no artificial delay.
        if (anyMeterCreated) {
          const elapsed = Date.now() - preCreateStartTime;
          const MIN_DISPLAY_MS = 1000;
          if (elapsed < MIN_DISPLAY_MS) {
            await new Promise<void>(resolve =>
              setTimeout(resolve, MIN_DISPLAY_MS - elapsed)
            );
          }
        }

        // All pre-creates confirmed done — clear phase before handing off
        setState(prev => ({
          ...prev,
          isPreCreating: false,
          currentMeterMachineName: null,
        }));
      }

      // ============================================================
      // Phase 2: Run variation check (only for online machines)
      // ============================================================
      if (variationMachines.length === 0) {
        // All machines are offline/non-SMIB — no SAS data to compare
        // against. The manually-created meters match collection values
        // exactly, so variation is trivially 0. Skip the API call entirely.
        console.log(
          '[preCreateThenCheck] ⏭️ No online machines — skipping variation check'
        );
        setState(prev => ({
          ...prev,
          isChecking: false,
          checkComplete: true,
          hasVariations: false,
          variationsData: {
            hasVariations: false,
            totalVariation: 0,
            machines: [],
          },
          error: null,
        }));
      } else {
        console.log(
          '[preCreateThenCheck] ▶️ Phase 2: running variation check'
        );
        await checkVariations(locationId, variationMachines, includeJackpot);
      }
    },
    [checkVariations]
  );

  /**
   * Reset to initial state
   */
  const reset = useCallback(() => {
    setState(DEFAULT_STATE);
    lastMachinesRef.current = null;
    if (debounceTimeoutRef.current) {
      clearTimeout(debounceTimeoutRef.current);
    }
  }, []);

  // ============================================================================
  // Effects
  // ============================================================================

  /**
   * Cleanup debounce timeout on unmount
   */
  useEffect(() => {
    return () => {
      if (debounceTimeoutRef.current) {
        clearTimeout(debounceTimeoutRef.current);
      }
    };
  }, []);

  return {
    // State
    isChecking: state.isChecking,
    checkComplete: state.checkComplete,
    hasVariations: state.hasVariations,
    variationsData: state.variationsData,
    error: state.error,
    isMinimized: state.isMinimized,
    isPreCreating: state.isPreCreating,
    currentMeterMachineName: state.currentMeterMachineName,
    meterCreationError: state.meterCreationError,

    // Methods
    checkVariations,
    preCreateThenCheck,
    triggerAutoCheck,
    toggleMinimize,
    reset,
  };
}

