1	/**
2	 * @module app/api/collection-reports/pre-create-meters
3	 *
4	 * Pre-creates or updates manual Meter document(s) for a single non-SMIB or
5	 * offline-SMIB machine BEFORE the variation check fires and BEFORE
6	 * createCollectionReport runs.
7	 *
8	 * Features:
9	 * - Returns early (skipped) for online SMIB machines — relay supplies meters.
10	 * - Idempotency via Collection.meterId: if meterId is already set the machine
11	 *   was already handled; updates existing meter(s) with current values.
12	 * - RAM clear: creates/updates 2 meter docs (pre-reset + post-reset); normal: 1 doc.
13	 * - For V2 sessions, sets locationSession on the meter for deleteMany safety.
14	 * - Returns customName fetched from the Machine doc for progress display.
15	 */
16	
17	import { NextRequest, NextResponse } from 'next/server';
18	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
19	import { Machine } from '@/app/api/lib/models/machines';
20	import { Meters } from '@/app/api/lib/models/meters';
21	import { Collections } from '@/app/api/lib/models/collections';
22	import { appendMeterIdsToCollections } from '@/app/api/lib/helpers/collectionReport/reportCreation';
23	import { generateMongoId } from '@/lib/utils/id';
24	import {
25	  logRouteRequest,
26	  logRouteCreate,
27	  logRouteWarn,
28	  logRouteError,
29	  extractUserFromRequest,
30	} from '@/app/api/lib/utils/routeLogger';
31	import type { GamingMachine, MeterDocument, MetersData } from '@/shared/types';
32	
33	const ROUTE_PATH = '/api/collection-reports/pre-create-meters';
34	const FUNCTION_NAME = 'POST /api/collection-reports/pre-create-meters';
35	
36	// ============================================================================
37	// Types
38	// ============================================================================
39	
40	type PreCreateMetersBody = {
41	  machineId: string;
42	  collectionId?: string;
43	  locationId: string;
44	  sessionId?: string;
45	  metersIn: number;
46	  metersOut: number;
47	  prevMetersIn: number;
48	  prevMetersOut: number;
49	  ramClear?: boolean;
50	  ramClearMetersIn?: number;
51	  ramClearMetersOut?: number;
52	  sasEndTime?: string;
53	};
54	
55	// ============================================================================
56	// POST handler
57	// ============================================================================
58	
59	/**
60	 * POST /api/collection-reports/pre-create-meters
61	 *
62	 * Steps:
63	 * 1. Validate required fields
64	 * 2. Fetch machine document (relayId, lastActivity, custom.name)
65	 * 3. Determine isNoSmibMachine / isOffline
66	 * 4. Skip if online SMIB (relay supplies meters)
67	 * 5. Skip if Collection already has meterId (idempotency guard for V1)
68	 * 6. Build meter document(s) — 2 for RAM clear, 1 otherwise
69	 * 7. Insert meters into DB
70	 * 8. Append meterId(s) to Collection doc (V1 only)
71	 * 9. Return result with customName for UI display
72	 */
73	export async function POST(req: NextRequest) {
74	  const user = extractUserFromRequest(req);
75	  return withApiAuth(req, async () => {
76	    const startTime = Date.now();
77	    logRouteRequest(FUNCTION_NAME, 'POST', ROUTE_PATH, user);
78	
79	    // ============================================================================
80	    // STEP 1: Parse and validate body
81	    // ============================================================================
82	    let body: PreCreateMetersBody;
83	    try {
84	      body = await req.json();
85	    } catch {
86	      logRouteError(FUNCTION_NAME, 'POST', ROUTE_PATH, 'Invalid JSON body', user);
87	      return NextResponse.json(
88	        { success: false, error: 'Invalid JSON body' },
89	        { status: 400 }
90	      );
91	    }
92	
93	    const {
94	      machineId,
95	      collectionId,
96	      locationId,
97	      sessionId,
98	      metersIn,
99	      metersOut,
100	      prevMetersIn,
101	      prevMetersOut,
102	      ramClear,
103	      ramClearMetersIn,
104	      ramClearMetersOut,
105	      sasEndTime,
106	    } = body;
107	
108	    console.log(
109	      `[pre-create-meters] ▶️ Request body: machine=${machineId} collection=${collectionId ?? 'none'} ` +
110	        `session=${sessionId ?? 'none'} location=${locationId} metersIn=${metersIn} metersOut=${metersOut} ` +
111	        `prevIn=${prevMetersIn} prevOut=${prevMetersOut} ramClear=${!!ramClear}`
112	    );
113	
114	    if (!machineId || !locationId || metersIn == null || metersOut == null) {
115	      logRouteError(
116	        FUNCTION_NAME,
117	        'POST',
118	        ROUTE_PATH,
119	        `Missing required fields: machineId=${machineId} locationId=${locationId} metersIn=${metersIn} metersOut=${metersOut}`,
120	        user
121	      );
122	      return NextResponse.json(
123	        { success: false, error: 'machineId, locationId, metersIn and metersOut are required' },
124	        { status: 400 }
125	      );
126	    }
127	
128	    // ============================================================================
129	    // STEP 2: Fetch machine document
130	    // ============================================================================
131	    const machineDoc = await Machine.findOne(
132	      { _id: machineId },
133	      'relayId lastActivity custom.name'
134	    ).lean<Pick<GamingMachine, 'relayId' | 'lastActivity' | 'custom'>>();
135	
136	    if (!machineDoc) {
137	      logRouteWarn(
138	        FUNCTION_NAME,
139	        'POST',
140	        ROUTE_PATH,
141	        `Machine not found: ${machineId} — cannot determine SMIB status`,
142	        user
143	      );
144	    }
145	
146	    const customName = machineDoc?.custom?.name ?? machineId;
147	
148	    // ============================================================================
149	    // STEP 3: Determine SMIB status
150	    // ============================================================================
151	    const hasRelay = !!machineDoc?.relayId;
152	    // const OFFLINE_THRESHOLD_MS = 72 * 60 * 60 * 1000; // 72 hours
153	    const OFFLINE_THRESHOLD_MS = 3 * 60 * 1000; // 3 minutes
154	    const lastActivityMs = machineDoc?.lastActivity
155	      ? new Date().getTime() - new Date(machineDoc.lastActivity).getTime()
156	      : null;
157	    const isOffline =
158	      hasRelay &&
159	      (!machineDoc?.lastActivity || (lastActivityMs !== null && lastActivityMs >= OFFLINE_THRESHOLD_MS));
160	    const smibStatus = !hasRelay
161	      ? 'NO-SMIB (no relayId → will create meter)'
162	      : isOffline
163	        ? 'OFFLINE SMIB (stale lastActivity → will create meter)'
164	        : 'ONLINE SMIB (relay supplies meters → will skip)';
165	
166	    console.log(
167	      `[pre-create-meters] 🔎 machine=${machineId} customName="${customName}" relayId=${machineDoc?.relayId ?? 'none'} ` +
168	        `hasRelay=${hasRelay} isOffline=${isOffline} ` +
169	        `lastActivityAgo=${lastActivityMs !== null ? `${Math.round(lastActivityMs / 1000)}s` : 'never'} ` +
170	        `→ ${smibStatus}`
171	    );
172	
173	    // ============================================================================
174	    // STEP 4: Skip online SMIB machines — relay creates meters automatically
175	    // ============================================================================
176	    if (hasRelay && !isOffline) {
177	      logRouteWarn(
178	        FUNCTION_NAME,
179	        'POST',
180	        ROUTE_PATH,
181	        `SKIPPED machine ${machineId} ("${customName}") — online SMIB, relay supplies meters (lastActivity ${lastActivityMs !== null ? `${Math.round(lastActivityMs / 1000)}s ago` : 'unknown'})`,
182	        user
183	      );
184	      if (Date.now() - startTime > 1000) {
185	        console.warn(`[pre-create-meters] Slow response: ${Date.now() - startTime}ms`);
186	      }
187	      return NextResponse.json({
188	        success: true,
189	        customName,
190	        created: false,
191	        skipped: true,
192	      });
193	    }
194	
195	    // ============================================================================
196	    // STEP 5: Check for existing meterId on Collection (update vs create)
197	    // ============================================================================
198	    let existingMeterId: string | undefined;
199	    let existingRamClearMeterId: string | undefined;
200	    if (collectionId) {
201	      const existingCollection = await Collections.findOne(
202	        { _id: collectionId },
203	        'meterId ramClearMeterId'
204	      ).lean<{ meterId?: string; ramClearMeterId?: string }>();
205	
206	      if (existingCollection?.meterId) {
207	        existingMeterId = existingCollection.meterId;
208	        existingRamClearMeterId = existingCollection.ramClearMeterId;
209	        console.log(
210	          `[pre-create-meters] 🔄 machine=${machineId} collection=${collectionId} — meterId ${existingMeterId} already set, will UPDATE existing meter(s)`
211	        );
212	      }
213	    }
214	
215	    // ============================================================================
216	    // STEP 6: Build meter document(s)
217	    // ============================================================================
218	    const baseReadAt = sasEndTime ? new Date(sasEndTime) : new Date();
219	    const baseCreatedAt = new Date();
220	
221	    let prevMeterDoc: MeterDocument | null = null;
222	    if (isOffline) {
223	      const prevMeterQuery = sessionId
224	        ? {
225	            machine: machineId,
226	            locationSession: { $ne: sessionId },
227	            readAt: { $lt: baseReadAt },
228	          }
229	        : {
230	            machine: machineId,
231	          };
232	      prevMeterDoc = await Meters.findOne(prevMeterQuery)
233	        .sort({ readAt: -1 })
234	        .lean<MeterDocument>();
235	    }
236	
237	    const metersToCreate: MetersData[] = [];
238	    const currentMetersIn = metersIn;
239	    const currentMetersOut = metersOut;
240	    const previousMetersIn = prevMetersIn ?? 0;
241	    const previousMetersOut = prevMetersOut ?? 0;
242	
243	    // Standard movement deltas
244	    let movementIn: number;
245	    let movementOut: number;
246	    if (isOffline && prevMeterDoc) {
247	      movementIn = Math.round((currentMetersIn - (prevMeterDoc.drop ?? 0)) * 100) / 100;
248	      movementOut = Math.round((currentMetersOut - (prevMeterDoc.totalCancelledCredits ?? 0)) * 100) / 100;
249	    } else {
250	      movementIn = currentMetersIn - previousMetersIn;
251	      movementOut = currentMetersOut - previousMetersOut;
252	    }
253	
254	    if (ramClear) {
255	      // RAM CLEAR: create 2 meter docs
256	      const ramClearIn = ramClearMetersIn ?? 0;
257	      const ramClearOut = ramClearMetersOut ?? 0;
258	
259	      const ramBaselineIn = isOffline && prevMeterDoc ? (prevMeterDoc.drop ?? 0) : previousMetersIn;
260	      const ramBaselineOut = isOffline && prevMeterDoc ? (prevMeterDoc.totalCancelledCredits ?? 0) : previousMetersOut;
261	      const ramMovementIn = Math.round((ramClearIn - ramBaselineIn) * 100) / 100;
262	      const ramMovementOut = Math.round((ramClearOut - ramBaselineOut) * 100) / 100;
263	
264	      const ramClearMeterId = existingRamClearMeterId || await generateMongoId();
265	      metersToCreate.push({
266	        _id: ramClearMeterId,
267	        machine: machineId,
268	        location: locationId,
269	        ...(sessionId ? { locationSession: sessionId } : {}),
270	        movement: {
271	          coinIn: 0,
272	          coinOut: 0,
273	          jackpot: 0,
274	          totalHandPaidCancelledCredits: 0,
275	          totalCancelledCredits: ramMovementOut,
276	          gamesPlayed: 0,
277	          gamesWon: 0,
278	          currentCredits: 0,
279	          totalWonCredits: 0,
280	          drop: ramMovementIn,
281	        },
282	        coinIn: isOffline && prevMeterDoc ? (prevMeterDoc.coinIn ?? 0) : 0,
283	        coinOut: isOffline && prevMeterDoc ? (prevMeterDoc.coinOut ?? 0) : 0,
284	        jackpot: isOffline && prevMeterDoc ? (prevMeterDoc.jackpot ?? 0) : 0,
285	        totalHandPaidCancelledCredits: isOffline && prevMeterDoc ? (prevMeterDoc.totalHandPaidCancelledCredits ?? 0) : 0,
286	        currentCredits: isOffline && prevMeterDoc ? (prevMeterDoc.currentCredits ?? 0) : 0,
287	        totalWonCredits: isOffline && prevMeterDoc ? (prevMeterDoc.totalWonCredits ?? 0) : 0,
288	        gamesPlayed: isOffline && prevMeterDoc ? (prevMeterDoc.gamesPlayed ?? 0) : 0,
289	        gamesWon: isOffline && prevMeterDoc ? (prevMeterDoc.gamesWon ?? 0) : 0,
290	        totalCancelledCredits: ramClearOut,
291	        drop: ramClearIn,
292	        meterSource: 'COLLECTION_REPORT' as const,
293	        isRamClear: true,
294	        isSupplemental: isOffline,
295	        readAt: new Date(baseReadAt.getTime() - 1000),
296	        createdAt: baseCreatedAt,
297	      });
298	
299	      const currentMeterId = existingMeterId || await generateMongoId();
300	      metersToCreate.push({
301	        _id: currentMeterId,
302	        machine: machineId,
303	        location: locationId,
304	        ...(sessionId ? { locationSession: sessionId } : {}),
305	        movement: {
306	          coinIn: 0,
307	          coinOut: 0,
308	          jackpot: 0,
309	          totalHandPaidCancelledCredits: 0,
310	          totalCancelledCredits: currentMetersOut,
311	          gamesPlayed: 0,
312	          gamesWon: 0,
313	          currentCredits: 0,
314	          totalWonCredits: 0,
315	          drop: currentMetersIn,
316	        },
317	        coinIn: 0,
318	        coinOut: 0,
319	        jackpot: 0,
320	        totalHandPaidCancelledCredits: 0,
321	        totalCancelledCredits: currentMetersOut,
322	        gamesPlayed: 0,
323	        gamesWon: 0,
324	        currentCredits: 0,
325	        totalWonCredits: 0,
326	        drop: currentMetersIn,
327	        meterSource: 'COLLECTION_REPORT' as const,
328	        isRamClear: false,
329	        isSupplemental: isOffline,
330	        readAt: new Date(baseReadAt.getTime() + 1000),
331	        createdAt: new Date(baseCreatedAt.getTime() + 1000),
332	      });
333	    } else {
334	      // NORMAL: create 1 meter doc
335	      const meterId = existingMeterId || await generateMongoId();
336	      metersToCreate.push({
337	        _id: meterId,
338	        machine: machineId,
339	        location: locationId,
