354	        coinOut: isOffline && prevMeterDoc ? (prevMeterDoc.coinOut ?? 0) : 0,
355	        jackpot: isOffline && prevMeterDoc ? (prevMeterDoc.jackpot ?? 0) : 0,
356	        totalHandPaidCancelledCredits: isOffline && prevMeterDoc ? (prevMeterDoc.totalHandPaidCancelledCredits ?? 0) : 0,
